      &XMLUserDefinedViews;












declare @taxType int, @taxAccount varchar(32), @taxCode varchar(32), @taxRate numeric(5,2)
select @taxRate = 0, @taxAccount = '', @taxType = 0, @taxCode = rtrim(val) from options where name = 'm_ma_thue_0'
if exists(select 1 from dmthue where ma_thue = @taxCode)
  select @taxRate = a.thue_suat, @taxAccount = rtrim(a.tk_thue_co), @taxType = isnull(b.tk_cn, 0) from dmthue a left join dmtk b on a.tk_thue_co = b.tk where a.ma_thue = @taxCode

select 'var t=this;t._taxCode =''' + rtrim(@taxCode) + ''';t._taxRate =''' + rtrim(@taxRate) + ''';t._taxAccount =''' + rtrim(@taxAccount) + ''';t._taxType =' + rtrim(@taxType) + ';t._voucherCode='@@id';load$GridVoucherDetail$(t);t.$a.AmountFormula=t.$a.&AmountFormula;;' as message
return






        select 'setDefaultValue$GridVoucherDetail(this.get_element().parentForm);' as message
return





        select 'dispose$GridVoucherDetail$(this);' as message
return








/* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia_nt_sl: '[gia_nt]:=([gia_nt] == 0 ? ([so_luong] != 0 ? ([tien_nt2]/[so_luong]) : 0) : [gia_nt])',
    gia_sl: '[gia]:=([gia] == 0 ? ([so_luong] != 0 ? ([tien2]/[so_luong]) : 0) : [gia])',

    gia_tg: '[gia]:=[gia_nt]*[$ty_gia]',
    tien_nt2_sl: '[tien_nt2]:=[so_luong]*[gia_nt]',
    tien2_sl: '[tien2]:=[so_luong]*[gia]',
    tien2: '[tien2]:=[tien_nt2]*[$ty_gia]',
    ck_nt: '[ck_nt]:=[tien_nt2]*[tl_ck]/100',
    ck_tg: '[ck]:=[ck_nt]*[$ty_gia]',
    ck_tl: '[ck]:=[tien2]*[tl_ck]/100',
    thue_nt: '[thue_nt]:=([tien_nt2] - [ck_nt])*[thue_suat]/100',
    thue_tl: '[thue]:=([tien2] - [ck])*[thue_suat]/100',
    thue_tg: '[thue]:=[thue_nt]*[$ty_gia]',

    t_tien_nt2: ['t_tien_nt2', 'tien_nt2'],
    t_tien2: ['t_tien2', 'tien2'],
    t_ck_nt: ['t_ck_nt', 'ck_nt'],
    t_ck: ['t_ck', 'ck'],
    t_thue_nt: ['t_thue_nt', 'thue_nt'],
    t_thue: ['t_thue', 'thue'],

    t_tt: '[t_tt]:=[t_tien2] - [t_ck]+[t_thue]',
    t_tt_nt: '[t_tt_nt]:=[t_tien_nt2] - [t_ck_nt]+[t_thue_nt]'
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_kh', 'ngay_lct', 'ma_tt', 'ma_nt'];
  udf$Detail$(g);
  udf$Detail$QuantityPrice(g);
}

function udf$Detail$QuantityPrice(g) {
 if (!g.get_element().parentForm._udfQuantityPrice) {
    udf$Field$(g, 'dvt');
    udf$Field$(g, 'so_luong');
    udf$Field$(g, 'gia_nt');
    udf$Field$(g, 'gia');
  }
}

function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}

function onChange$GridVoucherDetail$TaxCode(o) {o.grid.request(o, 'GetTaxRate', 'GetTaxRate', ['ma_thue']);}
function onChange$GridVoucherDetail$TaxAccount(o) {o.grid.request(o, 'TaxAccount', 'TaxAccount', ['tk_thue']);}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, [g.$a.tien_nt2_sl, g.$a.AmountFormula, g.$a.ck_nt, g.$a.ck_tl, g.$a.thue_nt, g.$a.thue_tl]);
      on$GridVoucherDetail$AmountChange(o, g, f);
      break;
    case 'gia_nt':
      g.validExpression(o, [g.$a.tien_nt2_sl, g.$a.gia_tg, g.$a.AmountFormula, g.$a.ck_nt, g.$a.ck_tl, g.$a.thue_nt, g.$a.thue_tl], null, null, 'tien_nt2');
      on$GridVoucherDetail$AmountChange(o, g, f);
      break;
    case 'tien_nt2':
      if (f._calPrice && f._udfQuantityPrice) g.validExpression(o, [g.$a.gia_nt_sl, g.$a.gia_tg]);
      g.validExpression(o, [g.$a.tien2, g.$a.ck_nt, g.$a.ck_tl, g.$a.thue_nt, g.$a.thue_tl]);
      on$GridVoucherDetail$AmountChange(o, g, f);
      break;
    case 'tl_ck':
      g.validExpression(o, [g.$a.ck_nt, g.$a.ck_tl, g.$a.thue_nt, g.$a.thue_tl]);
      on$GridVoucherDetail$AmountChange(o, g, f);
      break;
    case 'gia':
      g.validExpression(o, [g.$a.tien2_sl, g.$a.ck_tl, g.$a.thue_tl], [g.$a.t_ck, g.$a.t_thue, g.$a.t_tien2], [g.$a.t_tt], 'tien2');
      break;
    case 'tien2':
      if (f._calPrice && f._udfQuantityPrice) g.validExpression(o, [g.$a.gia_sl]);
      g.validExpression(o, [g.$a.ck_tl, g.$a.thue_tl], [g.$a.t_ck, g.$a.t_thue, g.$a.t_tien2], [g.$a.t_tt]);
      break;
    case 'ck_nt':
      g.validExpression(o, [g.$a.ck_tg, g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_ck_nt, g.$a.t_ck, g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'thue_nt':
      g.validExpression(o, [g.$a.thue_tg], [g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'ck':
      g.validExpression(o, [g.$a.thue_tl], [g.$a.t_ck, g.$a.t_thue], [g.$a.t_tt]);
      break;
    case 'thue':
      g.validExpression(o, null, [g.$a.t_thue], [g.$a.t_tt]);
    default:
      break;
  }
}

function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterInsertRow':
      setDefaultValue$GridVoucherDetail(f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
      g.validRowExpression('ma_kh2', '([ma_thue] == "") || (![tk_cn]) || ([ma_kh2] != "")');
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'GetTaxRate':
      var r = result[0].Value;
      if (g._getItemValue(o.row, g._getColumnOrder('thue_suat')) != r) {
        g.setItemGridBehavior(o, [['thue_suat', result[0].Value, '', null]]);
        g.validExpression(o, [g.$a.thue_nt, g.$a.thue_tl], [g.$a.t_thue_nt, g.$a.t_thue,g.$a.t_tien_nt2, g.$a.t_tien2], [g.$a.t_tt_nt, g.$a.t_tt]);
      }
      g.setItemGridBehavior(o, [['tk_thue', result[1].Value, '', null], ['tk_cn', result[2].Value, '', null]]);
      g.live(o, 'tk_thue');
      break;
    case 'TaxAccount':
      g.setItemGridBehavior(o, [['tk_cn', result[0].Value, '', null]]);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$RowChange(g, f) {
  g.executeAggregate([ g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_ck_nt, g.$a.t_ck, g.$a.t_thue_nt, g.$a.t_thue]);
  f.executeExpression([ g.$a.t_tt_nt, g.$a.t_tt]);
}
function on$GridVoucherDetail$AmountChange(o, g, f) {
  g.validExpression(g, null, [g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_ck_nt, g.$a.t_ck, g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
}
function setDefaultTaxItems(z, row, columns, f, fields) {
  for (var i = 0; i < columns.length; i++) {
    if (fields) setDefaultTaxItem(z, row, columns[i], f, fields[i]);
      else setDefaultTaxItem(z, row, columns[i], f[i]);
  }
}
function setDefaultTaxItem(z, row, columnName, f, fieldName) {
  if (fieldName != null) z._setItemValue(row, z._getColumnOrder(columnName), f.getItemValue(fieldName));
    else z._setItemValue(row, z._getColumnOrder(columnName), f);
}
function setDefaultValue$GridVoucherDetail(f){
  var g = f.getItem("d21")._controlBehavior;
  var r = g._rowCount;
  if ((r > 0) && (g._getItemValue(r, g._getColumnOrder('ma_thue')) == '')) {
    setDefaultTaxItems(g, r, ['ma_thue', 'thue_suat', 'tk_thue', 'tk_cn'], [g._taxCode, g._taxRate, g._taxAccount, g._taxType]);
  }
}
